import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx';
import './KhaiBaoCoSo.css';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
    const navigate = useNavigate();
    
    const initialFormState = {
        // Giữ nguyên tất cả các trường trong state của bạn
        tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
        loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
        tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
        soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
        mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
        loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
        loaiHinhCheBienGo: '', nguonGocGo: '', loaiCoSoDangKy: '',
        tenLamSan: '', tenKhoaHoc: '',
        issueDate: '', expiryDate: '', trangThai: 'Đang hoạt động',
        // Thêm trường mới cho động vật
        tenLoaiDongVat: '', soLuongDuc: 0, soLuongCai: 0, nguonGocGiong: '', maSoGiayPhepNuoi: ''
    };

    const [formData, setFormData] = useState(initialFormState);
    const [loading, setLoading] = useState(false);
    const [isAdmin, setIsAdmin] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });
    
    useEffect(() => {
      // Logic kiểm tra token và role của bạn
    }, [navigate]);

    // === DI CHUYỂN CONSOLE.LOG VÀO ĐÂY ===
    const handleChange = useCallback((e) => {
        const { name, value } = e.target;
        
        // Dòng console.log phải nằm BÊN TRONG hàm này
        console.log(`Đang cập nhật state: name='${name}', value='${value}'`);

        setFormData(prevData => ({
            ...prevData,
            [name]: value
        }));
    }, []);

    const resetForm = useCallback(() => {
        setFormData(initialFormState);
        setMessage({ type: '', text: '' });
    }, [initialFormState]);

    // Hàm handleSubmit và các hàm khác giữ nguyên...
    const handleSubmit = async (e) => {
      // ...
    };
    
    return (
        // Phần JSX của bạn giữ nguyên...
        <div className="khai-bao-container">
            {/* ... */}
        </div>
    );
}

export default KhaiBaoCoSo;
